import os, hashlib
def hashfile(filepath):
    blocksize = 65536
    hasher = hashlib.md5()

    with open(filepath,'rb') as file:

        buf = file.read(blocksize)
        while len(buf) > 0 :
            hasher.update(buf)
            buf = file.read(blocksize)

    return(hasher.hexdigest())

